class FfiTtl:
    def __init__(self):
        raise RuntimeError("FfiTtl cannot be instantiated directly")

    # Each enum variant is a nested class of the enum itself.
    class DEFAULT:
        def __init__(
            self,
        ):
            pass

        def __str__(self):
            return "FfiTtl.DEFAULT()".format()

        def __eq__(self, other):
            if not other.is_DEFAULT():
                return False
            return True

    class NO_EXPIRY:
        def __init__(
            self,
        ):
            pass

        def __str__(self):
            return "FfiTtl.NO_EXPIRY()".format()

        def __eq__(self, other):
            if not other.is_NO_EXPIRY():
                return False
            return True

    class EXPIRE_AFTER_TICKS:
        def __init__(self, *values):
            if len(values) != 1:
                raise TypeError(f"Expected 1 arguments, found {len(values)}")
            self._values = values

        def __getitem__(self, index):
            return self._values[index]

        def __str__(self):
            return f"FfiTtl.EXPIRE_AFTER_TICKS{self._values!r}"

        def __eq__(self, other):
            if not other.is_EXPIRE_AFTER_TICKS():
                return False
            return self._values == other._values

